    93→/**
    94→ * Detect pattern-based attributes using configured detectors
    95→ */
    96→function detectPatternAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
    97→  const detectors = config.attributes?.detectors || [];
    98→  const detectedAttributes: DetectedAttribute[] = [];
    99→
   100→  for (const detector of detectors) {
   101→    try {
   102→      const detection = applyDetector(email, detector);
   103→      if (detection.detected) {
   104→        detectedAttributes.push({
   105→          attribute_name: detector.attribute,
   106→          attribute_value: detection.value as string | number | boolean,
   107→          detection_method: 'pattern',
   108→          detection_evidence: detection.evidence || 'Pattern match',
   109→          confidence: 0.8, // Default confidence for pattern matches
   110→        });
   111→      }
   112→    } catch (error) {
   113→      // Log error but continue processing
   114→      console.warn(`Error applying detector for ${detector.attribute}:`, error);
   115→    }
   116→  }
   117→
