   120→
   121→/**
   122→ * Apply individual detector pattern to email content
   123→ */
   124→function applyDetector(
   125→  email: EmailMessage,
   126→  detector: AttributeDetector
   127→): { detected: boolean; value?: unknown; evidence?: string } {
   128→  const { field, operation, values } = detector;
   129→
   130→  // Get the field content to search
   131→  let searchContent = '';
   132→  switch (field) {
   133→  case 'body':
   134→    searchContent = email.bodyPlain || '';
   135→    break;
   136→  case 'subject':
   137→    searchContent = email.subject || '';
   138→    break;
   139→  case 'from.address':
   140→    searchContent = email.from?.email || '';
   141→    break;
   142→  case 'from.name':
   143→    searchContent = email.from?.name || '';
   144→    break;
   145→  default:
   146→    console.warn(`Unknown field type for detector: ${field}`);
   147→    return { detected: false };
   148→  }
   149→
   150→  // Apply detection operation
   151→  switch (operation) {
   152→  case 'contains_any':
   153→    for (const value of values) {
   154→      if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   155→        return {
   156→          detected: true,
   157→          value: true,
   158→          evidence: `Found "${value}" in ${field}`,
   159→        };
   160→      }
   161→    }
   162→    break;
   163→
   164→  case 'regex_any':
   165→    for (const pattern of values) {
   166→      try {
   167→        const regex = new RegExp(pattern, 'ig'); // Add global flag for better matching
   168→        const match = searchContent.match(regex);
   169→        if (match) {
   170→          // For amount patterns, try to match the longest currency pattern
   171→          let bestMatch = match[0];
   172→          if (pattern.includes('\\$\\d+')) {
   173→            // Special handling for currency amounts - match full amounts with decimals
   174→            const fullAmountRegex = /\$\d+(?:\.\d{2})?/g;
   175→            const fullMatches = searchContent.match(fullAmountRegex);
   176→            if (fullMatches && fullMatches.length > 0) {
   177→              bestMatch = fullMatches[0]; // Use the first full amount match
   178→            }
   179→          }
   180→          return {
   181→            detected: true,
   182→            value: true,
   183→            evidence: `Regex "${pattern}" matched: "${bestMatch}" in ${field}`,
   184→          };
   185→        }
   186→      } catch (error) {
   187→        console.warn(`Invalid regex pattern: ${pattern}`, error);
   188→        continue;
   189→      }
   190→    }
   191→    break;
   192→
   193→  case 'starts_with':
   194→    for (const value of values) {
   195→      if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
   196→        return {
   197→          detected: true,
   198→          value: true,
   199→          evidence: `${field} starts with "${value}"`,
   200→        };
   201→      }
   202→    }
   203→    break;
   204→
   205→  case 'ends_with':
   206→    for (const value of values) {
   207→      if (searchContent.toLowerCase().endsWith(value.toLowerCase())) {
   208→        return {
   209→          detected: true,
   210→          value: true,
   211→          evidence: `${field} ends with "${value}"`,
   212→        };
   213→      }
   214→    }
   215→    break;
   216→
   217→  default:
   218→    console.warn(`Unknown operation type: ${operation}`);
   219→  }
   220→
   221→  return { detected: false };
   222→}
   223→
   224→/**
   225→ * Detect derived attributes using logical rules
   226→ */
   227→function detectDerivedAttributes(email: EmailMessage, config: AttributeDetectionStageConfig): DetectedAttribute[] {
   228→  const settings = config.settings?.attribute_processing;
   229→  const detectedAttributes: DetectedAttribute[] = [];
   230→
   231→  // Derive self_sent attribute (if enabled, default true)
   232→  const detectSelfSent = !settings || settings.detect_self_sent !== false;
   233→  if (detectSelfSent) {
   234→    const selfSent = deriveSelfSent(email);
   235→    if (selfSent) {
   236→      detectedAttributes.push(selfSent);
   237→    }
   238→  }
   239→
   240→  // Domain-based derivations (if enabled, default true)
   241→  const resolveDomains = !settings || settings.resolve_domains !== false;
   242→  if (resolveDomains) {
