   265→/**
   266→ * Derive self_sent attribute - email sent from user to self
   267→ */
   268→function deriveSelfSent(email: EmailMessage): DetectedAttribute | null {
   269→  const userAddresses = getUserAddresses();
   270→  const fromAddress = email.from?.email?.toLowerCase();
   271→
   272→  // Check if from address is user address
   273→  if (!fromAddress || !userAddresses.includes(fromAddress)) {
   274→    return null;
   275→  }
   276→
   277→  // Check if all recipients are user addresses
   278→  const allRecipients: string[] = [];
   279→  if (email.to) {
