   281→  }
   282→  if (email.cc) {
   283→    allRecipients.push(...email.cc.map((addr) => addr.email.toLowerCase()));
   284→  }
   285→  if (email.bcc) {
   286→    allRecipients.push(...email.bcc.map((addr) => addr.email.toLowerCase()));
   287→  }
   288→
   289→  const allRecipientsAreUser = allRecipients.length > 0 && allRecipients.every((addr) => userAddresses.includes(addr));
   290→
   291→  // Check for List-Id header (exclude mailing lists)
   292→  const hasListId = email.payload?.headers?.some((header) => header.name.toLowerCase() === 'list-id');
   293→
   294→  if (allRecipientsAreUser && !hasListId) {
