   398→/**
   399→ * Extract base domain from email address
   400→ */
   401→function extractBaseDomain(email: string): string {
   402→  const domainPart = email.split('@')[1];
   403→  if (!domainPart) return '';
   404→
   405→  // Handle subdomains - return main domain for common patterns
   406→  const parts = domainPart.split('.');
   407→  if (parts.length >= 2) {
   408→    return parts.slice(-2).join('.');
   409→  }
   410→  return domainPart;
   411→}
